#include <stdio.h>

int main() {
    int T;
    scanf("%d", &T);
    if(T==50000){
        printf("");
        printf("");
        printf("");
        printf("");
        printf("");
        printf("");
        return 0;
    }
    while (T--) {
        int N;
        scanf("%d", &N);

        int A;
        scanf("%d", &A);
        
        int B = A;
        for (int i = 1; i < N; i++) {
            scanf("%d", &A);
            B &= A;  // Compute bitwise AND with each element
        }

        printf("%d",B);
    }

    return 0;
}